Add the prompt-specific filters to the PromptWorld Jinja environment. These are used by templates like REPLHistory.

Location: crates/baml-bridge/src/prompt/jinja.rs

```rust
use minijinja::{Environment, Value, Error};

/// Register prompt-specific filters
pub fn register_prompt_filters(env: &mut Environment<'static>) {
    env.add_filter('truncate', filter_truncate);
    env.add_filter('slice_chars', filter_slice_chars);
    env.add_filter('format_count', filter_format_count);
}

/// Truncate string to n characters, adding '...' suffix if truncated
fn filter_truncate(s: &str, n: usize) -> String {
    if s.chars().count() <= n {
        s.to_string()
    } else {
        let truncated: String = s.chars().take(n.saturating_sub(3)).collect();
        format!('{}...', truncated)
    }
}

/// Slice first n characters (no suffix)
fn filter_slice_chars(s: &str, n: usize) -> String {
    s.chars().take(n).collect()
}

/// Format number with thousands separators: 12345 -> '12,345'
fn filter_format_count(n: i64) -> String {
    let s = n.abs().to_string();
    let mut result = String::new();
    let sign = if n < 0 { '-' } else { '' };

    for (i, c) in s.chars().rev().enumerate() {
        if i > 0 && i % 3 == 0 {
            result.push(',');
        }
        result.push(c);
    }

    format!('{}{}'.sign, result.chars().rev().collect::<String>())
}
```

These match the filters used in existing REPLHistory templates:
- {{ output | slice_chars(max_output_chars) }}
- {{ output_len | format_count }}
- {{ s | truncate(100) }}

Implement RenderSession - the per-render-invocation context that tracks depth, recursion guards, and custom template context.

Location: crates/baml-bridge/src/prompt/renderer.rs

```rust
/// Per-render context (one per render_messages call)
pub struct RenderSession {
    /// Settings (can override world defaults)
    pub settings: RenderSettings,

    /// Custom template context (e.g., { max_output_chars: 5000 })
    /// Passed to templates as 'ctx'
    pub ctx: minijinja::Value,

    /// Current recursion depth
    pub depth: usize,

    /// Recursion guard stack: (TypeKey, path) pairs
    pub stack: Vec<(TypeKey, String)>,
}

impl RenderSession {
    pub fn new(settings: RenderSettings) -> Self {
        Self {
            settings,
            ctx: minijinja::Value::UNDEFINED,
            depth: 0,
            stack: Vec::new(),
        }
    }

    pub fn with_ctx<T: serde::Serialize>(mut self, ctx: T) -> Self {
        self.ctx = minijinja::Value::from_serialize(&ctx);
        self
    }

    pub fn push_depth(&self) -> Self {
        let mut new = self.clone();
        new.depth += 1;
        new
    }

    pub fn check_recursion(&self, key: &TypeKey) -> bool {
        self.stack.iter().any(|(k, _)| k == key)
    }
}
```

The session is cloned/modified for child renders - it's not shared state. Accept impl Serialize for ctx so dspy-rs callers don't need minijinja dependency directly.

